impl eframe::App for EditorApp { fn update(&mut self, ctx: &egui::Context, _frame: &mut eframe::Frame) { egui::TopBottomPanel::top("top_panel").show(ctx, |ui| { ui.horizontal_wrapped(|ui| { for name in self.api.buffers.keys() { if ui.selectable_label(self.api.active_buffer == *name, name).clicked() { self.api.active_buffer = name.clone(); } } }); }); egui::CentralPanel::default().show(ctx, |ui| { let text_edit = egui::TextEdit::multiline(&mut self.api.buffers.get_mut(&self.api.active_buffer).unwrap().lines[0]) .desired_width(f32::INFINITY); ui.add_sized(ui.available_size(), text_edit); }); egui::Area::new("fab_area").anchor(egui::Align2::RIGHT_BOTTOM, egui::vec2(-16.0, -16.0)).show(ctx, |ui| { if ui.button("📁 Acciones").clicked() { self.api.menu_open = !self.api.menu_open; } }); if self.api.menu_open { egui::Window::new("Menú").collapsible(false).show(ctx, |ui| { if ui.button("💾 Guardar").clicked() { let content = self.api.buffers.get(&self.api.active_buffer).unwrap().lines[0].clone(); std::fs::write(&self.api.active_buffer, content).expect("Error al guardar"); self.api.menu_open = false; } if ui.button("📄 Nuevo").clicked() { println!("Creando nuevo..."); self.api.menu_open = false; } }); } } fn on_exit(&mut self, _gl: Option<&eframe::glow::Context>) { println!("Guardando..."); } }
